css:
.loader {color: var(--loader-color, #94a3b8);
  --loader-secondary-color: #cbd5e1;
  --loader-bg: #f8fafc;

  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 10px;
}
.loader .avatar,
.loader .line {
  background: color-mix(in srgb, var(--loader-color, #94a3b8) 65%, var(--loader-bg, #f8fafc));
  animation: skeletonPulse var(--loader-speed, 1.2s) ease-in-out infinite;
}
.loader .avatar {
  width: 48px;
  height: 48px;
  border-radius: 999px;
}
.loader .lines {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.loader .line {
  height: 20px;
  border-radius: 999px;
}
.loader .line-short { width: 112px; }
.loader .line-long { width: 144px; }
@keyframes skeletonPulse {
  0%, 100% { opacity: .45; }
  50% { opacity: 1; }
}
